| MCP:mewF8v | subprojects {
| MCP:mewF8v |     apply plugin: 'java'
| MCP:mewF8v |     apply plugin: 'io.spring.javaformat'
| MCP:mewF8v | 
| MCP:mewF8v |     dependencies {
| MCP:mewF8v |         compileOnly "io.spring.javaformat:spring-javaformat-gradle-plugin:${springJavaFormatVersion}"
| MCP:mewF8v |     }
| MCP:mewF8v | }

| MCP:mewF8v | plugins {
| MCP:mewF8v |     id 'java-library'
| MCP:mewF8v |     id 'org.springframework.boot' apply(false)
| MCP:mewF8v |     id 'io.spring.dependency-management'
| MCP:mewF8v |     id 'io.spring.javaformat' apply(false)
| MCP:mewF8v |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:mewF8v | }
| MCP:mewF8v | 
| MCP:mewF8v | apply from: 'lint.gradle'
| MCP:mewF8v | 
| MCP:mewF8v | allprojects {
| MCP:mewF8v |     group = "${projectGroup}"
| MCP:mewF8v |     version = "${applicationVersion}"
| MCP:mewF8v | 
| MCP:mewF8v |     repositories {
| MCP:mewF8v |         mavenCentral()
| MCP:mewF8v |     }
| MCP:mewF8v | }
| MCP:mewF8v | 
| MCP:mewF8v | subprojects {
| MCP:mewF8v |     apply plugin: 'java-library'
| MCP:mewF8v |     apply plugin: 'org.springframework.boot'
| MCP:mewF8v |     apply plugin: 'io.spring.dependency-management'
| MCP:mewF8v |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:mewF8v |     
| MCP:mewF8v |     dependencyManagement {
| MCP:mewF8v |         imports {
| MCP:mewF8v |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:mewF8v |         }
| MCP:mewF8v |     }
| MCP:mewF8v | 
| MCP:mewF8v |     dependencies {
| MCP:mewF8v |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:mewF8v |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:mewF8v |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:mewF8v |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:mewF8v |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:mewF8v |         testImplementation 'org.assertj:assertj-core'
| MCP:mewF8v |         testImplementation 'org.mockito:mockito-core'
| MCP:mewF8v |     }
| MCP:mewF8v | 
| MCP:mewF8v |     java {
| MCP:mewF8v |         toolchain {
| MCP:mewF8v |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:mewF8v |         }
| MCP:mewF8v |     }
| MCP:mewF8v | 
| MCP:mewF8v |     bootJar.enabled = false
| MCP:mewF8v |     jar.enabled = true
| MCP:mewF8v | 
| MCP:mewF8v |     test {
| MCP:mewF8v |         useJUnitPlatform {
| MCP:mewF8v |             excludeTags 'develop', 'restdocs'
| MCP:mewF8v |         }
| MCP:mewF8v |     }
| MCP:mewF8v | 
| MCP:mewF8v |     testing {
| MCP:mewF8v |         suites {
| MCP:mewF8v |             test {
| MCP:mewF8v |                 targets {
| MCP:mewF8v |                     unitTest {
| MCP:mewF8v |                         testTask.configure {
| MCP:mewF8v |                             group = 'verification'
| MCP:mewF8v |                             useJUnitPlatform {
| MCP:mewF8v |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:mewF8v |                             }
| MCP:mewF8v |                         }
| MCP:mewF8v |                     }
| MCP:mewF8v | 
| MCP:mewF8v |                     contextTest {
| MCP:mewF8v |                         testTask.configure {
| MCP:mewF8v |                             group = 'verification'
| MCP:mewF8v |                             useJUnitPlatform {
| MCP:mewF8v |                                 includeTags 'context'
| MCP:mewF8v |                             }
| MCP:mewF8v |                         }
| MCP:mewF8v |                     }
| MCP:mewF8v | 
| MCP:mewF8v |                     restDocsTest {
| MCP:mewF8v |                         testTask.configure {
| MCP:mewF8v |                             group = 'verification'
| MCP:mewF8v |                             useJUnitPlatform {
| MCP:mewF8v |                                 includeTags 'restdocs'
| MCP:mewF8v |                             }
| MCP:mewF8v |                         }
| MCP:mewF8v |                     }
| MCP:mewF8v | 
| MCP:mewF8v |                     developTest {
| MCP:mewF8v |                         testTask.configure {
| MCP:mewF8v |                             group = 'verification'
| MCP:mewF8v |                             useJUnitPlatform {
| MCP:mewF8v |                                 includeTags 'develop'
| MCP:mewF8v |                             }
| MCP:mewF8v |                         }
| MCP:mewF8v |                     }
| MCP:mewF8v |                 }
| MCP:mewF8v |             }
| MCP:mewF8v |         }
| MCP:mewF8v |     }
| MCP:mewF8v | 
| MCP:mewF8v |     tasks.named('asciidoctor').configure {
| MCP:mewF8v |         dependsOn restDocsTest
| MCP:mewF8v |     }
| MCP:mewF8v | }
